import{c as p,Q as i,j as a,m as l}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"Pipe 管道","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/ipc/pipe.md","filePath":"document/kernel/ipc/pipe.md","lastUpdated":1777209094000}'),o={name:"document/kernel/ipc/pipe.md"};function c(d,e,r,t,n,s){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="pipe-管道" tabindex="-1">Pipe 管道 <a class="header-anchor" href="#pipe-管道" aria-label="Permalink to &quot;Pipe 管道&quot;">​</a></h1><blockquote><p>里程碑: <code>031_gui_native_app</code> (Phase 1-2)</p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>4KB 环形缓冲区单向管道，通过 VFS InodeOps 适配，实现进程间字节流通信。<code>sys_pipe</code> 系统调用创建一对 fd (读端/写端)。</p><h2 id="pipe-类-kernel-ipc-pipe-hpp-cpp" tabindex="-1">Pipe 类 (<code>kernel/ipc/pipe.hpp/cpp</code>) <a class="header-anchor" href="#pipe-类-kernel-ipc-pipe-hpp-cpp" aria-label="Permalink to &quot;Pipe 类 (`kernel/ipc/pipe.hpp/cpp`)&quot;">​</a></h2><ul><li>4KB 环形缓冲区</li><li><code>write(data, len)</code> — 写入 (满时 spin-wait 阻塞)</li><li><code>read(buf, len)</code> — 读取</li><li><code>close()</code> — 关闭管道</li><li>Spinlock 保护内部状态</li></ul><h2 id="vfs-适配-kernel-ipc-pipe-ops-hpp-cpp" tabindex="-1">VFS 适配 (<code>kernel/ipc/pipe_ops.hpp/cpp</code>) <a class="header-anchor" href="#vfs-适配-kernel-ipc-pipe-ops-hpp-cpp" aria-label="Permalink to &quot;VFS 适配 (`kernel/ipc/pipe_ops.hpp/cpp`)&quot;">​</a></h2><ul><li><code>PipeReadOps</code> — InodeOps 读方向适配</li><li><code>PipeWriteOps</code> — InodeOps 写方向适配</li><li>通过 <code>sys_read/sys_write</code> 自然支持 pipe fd</li></ul><h2 id="系统调用" tabindex="-1">系统调用 <a class="header-anchor" href="#系统调用" aria-label="Permalink to &quot;系统调用&quot;">​</a></h2><ul><li><code>sys_pipe(fd_pair)</code> — 创建 pipe，返回 [read_fd, write_fd]</li><li>FDTable 扩展: <code>set()</code> 方法支持手动设置 fd 0/1</li></ul><h2 id="集成" tabindex="-1">集成 <a class="header-anchor" href="#集成" aria-label="Permalink to &quot;集成&quot;">​</a></h2><ul><li>Terminal 窗口通过 pipe 连接 shell: stdin → pipe → shell stdin, shell stdout → pipe → Terminal</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/ipc/pipe.hpp/cpp</code> — Pipe 实现</li><li><code>kernel/ipc/pipe_ops.hpp/cpp</code> — VFS InodeOps 适配</li></ul>',14)])])}const _=p(o,[["render",c]]);export{u as __pageData,_ as default};
